    /** Updates a named endpoint via callback */
    withEndpointCallback(endpointName: string, callback: (obj: EndpointUpdateContext) => Promise<void>, options?: WithEndpointCallbackOptions): ViteAppResourcePromise;
    /** Updates an HTTP endpoint via callback */
    withHttpEndpointCallback(callback: (obj: EndpointUpdateContext) => Promise<void>, options?: WithHttpEndpointCallbackOptions): ViteAppResourcePromise;
    /** Updates an HTTPS endpoint via callback */
    withHttpsEndpointCallback(callback: (obj: EndpointUpdateContext) => Promise<void>, options?: WithHttpsEndpointCallbackOptions): ViteAppResourcePromise;
